import{_ as l,c as t,o as i,a5 as r,j as a}from"./chunks/framework.Dtwt352Q.js";const g=JSON.parse('{"title":"v1.1.14：TUI 交互体验大升级","description":"","frontmatter":{},"headers":[],"relativePath":"changelog/v1.1.14.md","filePath":"changelog/v1.1.14.md","lastUpdated":1772014034000}'),o={name:"changelog/v1.1.14.md"};function h(n,e,d,s,c,p){return i(),t("div",null,[...e[0]||(e[0]=[r('<h1 id="v1-1-14-tui-交互体验大升级" tabindex="-1">v1.1.14：TUI 交互体验大升级 <a class="header-anchor" href="#v1-1-14-tui-交互体验大升级" aria-label="Permalink to “v1.1.14：TUI 交互体验大升级”">​</a></h1><p><strong>发布日期</strong>：2026年1月12日</p><hr><h2 id="一句话总结" tabindex="-1">一句话总结 <a class="header-anchor" href="#一句话总结" aria-label="Permalink to “一句话总结”">​</a></h2><p>这次更新让 <strong>TUI 终端界面的鼠标交互更顺滑</strong>，自动补全、问答选项都支持鼠标悬停和点击了，还修复了粘贴文本时光标位置错误的问题。</p><hr><h2 id="新功能-鼠标交互全面升级" tabindex="-1">新功能：鼠标交互全面升级 <a class="header-anchor" href="#新功能-鼠标交互全面升级" aria-label="Permalink to “新功能：鼠标交互全面升级”">​</a></h2><h3 id="这次更新了什么" tabindex="-1">这次更新了什么？ <a class="header-anchor" href="#这次更新了什么" aria-label="Permalink to “这次更新了什么？”">​</a></h3><p>TUI（终端界面）现在支持更多鼠标操作：</p><ul><li><strong>自动补全</strong>：鼠标悬停高亮、点击选择</li><li><strong>问答选项</strong>：鼠标悬停高亮、点击选择</li><li><strong>子代理标题</strong>：点击可跳转</li></ul><h3 id="为什么这很重要" tabindex="-1">为什么这很重要？ <a class="header-anchor" href="#为什么这很重要" aria-label="Permalink to “为什么这很重要？”">​</a></h3><p>之前在 TUI 中，很多操作只能用键盘。现在你可以：</p><ol><li>用鼠标点击自动补全的选项，不用按方向键</li><li>用鼠标点击问答选项，不用输入数字</li><li>点击子代理标题，快速查看详情</li></ol><p><strong>简单说</strong>：键盘党继续用键盘，鼠标党也能愉快使用了。</p><hr><h2 id="问题修复-粘贴文本光标位置正确了" tabindex="-1">问题修复：粘贴文本光标位置正确了 <a class="header-anchor" href="#问题修复-粘贴文本光标位置正确了" aria-label="Permalink to “问题修复：粘贴文本光标位置正确了”">​</a></h2><h3 id="之前的问题" tabindex="-1">之前的问题 <a class="header-anchor" href="#之前的问题" aria-label="Permalink to “之前的问题”">​</a></h3><p>在 TUI 中粘贴单行文本后，光标位置会跑到错误的地方，导致继续输入时文字位置不对。</p><h3 id="现在的情况" tabindex="-1">现在的情况 <a class="header-anchor" href="#现在的情况" aria-label="Permalink to “现在的情况”">​</a></h3><p>粘贴后光标会正确停在文本末尾，可以继续流畅输入。</p><hr><h2 id="问题修复-斜杠命令补全不再跳动" tabindex="-1">问题修复：斜杠命令补全不再跳动 <a class="header-anchor" href="#问题修复-斜杠命令补全不再跳动" aria-label="Permalink to “问题修复：斜杠命令补全不再跳动”">​</a></h2><h3 id="之前的问题-1" tabindex="-1">之前的问题 <a class="header-anchor" href="#之前的问题-1" aria-label="Permalink to “之前的问题”">​</a></h3><p>输入 <code>/</code> 后，自动补全列表的高亮行会莫名其妙地跳来跳去。</p><h3 id="现在的情况-1" tabindex="-1">现在的情况 <a class="header-anchor" href="#现在的情况-1" aria-label="Permalink to “现在的情况”">​</a></h3><p>高亮行稳定了，选择命令更顺畅。</p><hr><h2 id="其他改进" tabindex="-1">其他改进 <a class="header-anchor" href="#其他改进" aria-label="Permalink to “其他改进”">​</a></h2><h3 id="desktop-桌面版" tabindex="-1">Desktop 桌面版 <a class="header-anchor" href="#desktop-桌面版" aria-label="Permalink to “Desktop 桌面版”">​</a></h3><ul><li><strong>图片预览</strong>：附件中的图片现在可以直接预览，不用打开外部程序</li></ul><h3 id="core-核心" tabindex="-1">Core 核心 <a class="header-anchor" href="#core-核心" aria-label="Permalink to “Core 核心”">​</a></h3><ul><li><strong>MCP 工具输出</strong>：支持 <code>resource</code> 内容类型</li><li><strong>外部目录权限</strong>：子目录权限检查更准确</li><li><strong>OAuth 登录</strong>：设备码不可用时自动复制 URL</li></ul><hr><h2 id="要不要升级" tabindex="-1">要不要升级？ <a class="header-anchor" href="#要不要升级" aria-label="Permalink to “要不要升级？”">​</a></h2><table tabindex="0"><thead><tr><th>情况</th><th>建议</th></tr></thead><tbody><tr><td>经常用 TUI 终端界面</td><td>✅ 升级，体验更好</td></tr><tr><td>之前遇到粘贴光标问题</td><td>✅ 升级</td></tr><tr><td>主要用 Desktop 桌面版</td><td>可以升级，有图片预览</td></tr><tr><td>用得好好的</td><td>可以等下次</td></tr></tbody></table><p><strong>升级命令</strong>：</p>',36),a("div",{class:"language-bash"},[a("button",{title:"Copy Code",class:"copy"}),a("span",{class:"lang"},"bash"),a("pre",null,[a("code",{"v-pre":""},"opencode upgrade")])],-1),r('<hr><h2 id="技术细节-可跳过" tabindex="-1">技术细节（可跳过） <a class="header-anchor" href="#技术细节-可跳过" aria-label="Permalink to “技术细节（可跳过）”">​</a></h2><details><summary>点击展开完整更新列表</summary><h3 id="core-核心-1" tabindex="-1">Core（核心） <a class="header-anchor" href="#core-核心-1" aria-label="Permalink to “Core（核心）”">​</a></h3><ul><li>支持 MCP 工具输出中的 <code>resource</code> 内容类型（@antigremlin）</li><li>检查子目录的外部目录权限（@dmmulroy）</li><li>升级 Copilot 插件版本</li></ul><h3 id="tui-终端界面" tabindex="-1">TUI（终端界面） <a class="header-anchor" href="#tui-终端界面" aria-label="Permalink to “TUI（终端界面）”">​</a></h3><ul><li>添加子代理标题的点击导航</li><li>问答工具支持鼠标悬停和点击（@indeep99）</li><li>修复 prompt ref 初始化，防止未定义引用错误</li><li>重构事件流，使用 SDK 替代手动 RPC 订阅</li><li>修复粘贴单行文本时的光标位置（@Octane0411）</li><li>自动补全支持鼠标悬停和点击（@kitlangton）</li><li>设备码不可用时复制 OAuth URL（@itskingori）</li><li>修复斜杠命令补全高亮行跳动问题（@kitlangton）</li></ul><h3 id="desktop-桌面版-1" tabindex="-1">Desktop（桌面版） <a class="header-anchor" href="#desktop-桌面版-1" aria-label="Permalink to “Desktop（桌面版）”">​</a></h3><ul><li>图片附件支持预览（@dbpolito）</li></ul><h3 id="社区贡献" tabindex="-1">社区贡献 <a class="header-anchor" href="#社区贡献" aria-label="Permalink to “社区贡献”">​</a></h3><p>感谢 10 位社区贡献者：@kitlangton、@itskingori、@zeke、@dbpolito、@jacobwgillespie、@dmmulroy、@Octane0411、@indeep99、@antigremlin、@eyalch</p></details><hr><p><a href="./">← 返回更新日志</a></p>',5)])])}const m=l(o,[["render",h]]);export{g as __pageData,m as default};
